import os
import uuid
import imghdr
from functools import wraps
from io import BytesIO

from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename
from PIL import Image

app = Flask(__name__)

# Configuration
app.config['UPLOAD_FOLDER'] = os.path.join(os.path.abspath(os.path.dirname(__file__)), 'uploads', 'profile_pictures')
app.config['MAX_CONTENT_LENGTH'] = 5 * 1024 * 1024  # 5 MB max upload size
app.config['MAX_IMAGE_DIMENSION'] = 2048  # Max width/height in pixels
app.config['THUMBNAIL_SIZE'] = (256, 256)  # Profile picture thumbnail size
app.config['ALLOWED_EXTENSIONS'] = {'png', 'jpg', 'jpeg', 'gif', 'webp'}
app.config['ALLOWED_MIME_TYPES'] = {
    'image/png',
    'image/jpeg',
    'image/gif',
    'image/webp',
}
# Mapping from imghdr detection to allowed types
IMGHDR_TO_EXT = {
    'png': 'png',
    'jpeg': 'jpg',
    'gif': 'gif',
    'webp': 'webp',
}

# Ensure upload directory exists
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)


def allowed_extension(filename):
    """Check if the file extension is allowed."""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']


def validate_image_content(file_stream):
    """
    Validate the actual content of the file by reading magic bytes.
    Returns the detected image type or None if invalid.
    """
    header = file_stream.read(32)
    file_stream.seek(0)
    detected_type = imghdr.what(None, h=header)

    # imghdr doesn't detect webp by default, handle manually
    if detected_type is None:
        if header[:4] == b'RIFF' and header[8:12] == b'WEBP':
            detected_type = 'webp'

    return detected_type if detected_type in IMGHDR_TO_EXT else None


def validate_image_with_pil(file_stream):
    """
    Open the image with PIL to verify it's a valid image file.
    Also checks for decompression bombs and oversized images.
    Returns (Image, error_message) tuple.
    """
    try:
        # Set a reasonable pixel limit to prevent decompression bombs
        Image.MAX_IMAGE_PIXELS = 25_000_000  # ~25 megapixels

        img = Image.open(file_stream)
        img.verify()  # Verify it's a valid image

        # Re-open after verify (verify closes the file)
        file_stream.seek(0)
        img = Image.open(file_stream)

        # Check dimensions
        width, height = img.size
        max_dim = app.config['MAX_IMAGE_DIMENSION']
        if width > max_dim or height > max_dim:
            return None, f"Image dimensions too large. Maximum allowed: {max_dim}x{max_dim} pixels."

        return img, None

    except Image.DecompressionBombError:
        return None, "Image is too large (possible decompression bomb)."
    except Exception as e:
        return None, f"Invalid or corrupted image file: {str(e)}"


def process_and_save_image(img, save_path):
    """
    Process the image: strip metadata, resize to thumbnail, convert to RGB if needed,
    and save to the specified path.
    """
    # Convert to RGB if necessary (handles RGBA, P mode, etc.)
    if img.mode in ('RGBA', 'LA', 'P'):
        # Create white background for transparency
        background = Image.new('RGB', img.size, (255, 255, 255))
        if img.mode == 'P':
            img = img.convert('RGBA')
        background.paste(img, mask=img.split()[-1] if 'A' in img.mode else None)
        img = background
    elif img.mode != 'RGB':
        img = img.convert('RGB')

    # Resize to thumbnail size while maintaining aspect ratio
    img.thumbnail(app.config['THUMBNAIL_SIZE'], Image.LANCZOS)

    # Save without metadata (exif data stripped by creating new image)
    clean_img = Image.new('RGB', img.size)
    clean_img.paste(img)
    clean_img.save(save_path, format='JPEG', quality=85, optimize=True)

    return clean_img.size


def require_auth(f):
    """Simple authentication decorator placeholder."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # In production, implement proper authentication (JWT, session, etc.)
        user_id = request.headers.get('X-User-ID')
        if not user_id:
            return jsonify({'error': 'Authentication required. Provide X-User-ID header.'}), 401
        # Basic validation of user_id format
        try:
            user_id = str(int(user_id))  # Ensure it's a valid integer string
        except (ValueError, TypeError):
            return jsonify({'error': 'Invalid user ID format.'}), 400
        kwargs['user_id'] = user_id
        return f(*args, **kwargs)
    return decorated_function


@app.route('/api/profile/picture', methods=['POST'])
@require_auth
def upload_profile_picture(user_id):
    """
    Upload a profile picture for the authenticated user.

    Expects a multipart/form-data request with a 'file' field containing the image.

    Validations:
    - File presence and non-empty filename
    - File extension whitelist
    - MIME type check
    - Magic bytes content validation
    - PIL image verification (catches corrupted files)
    - Dimension limits
    - File size limit (enforced by MAX_CONTENT_LENGTH)
    - Decompression bomb protection

    Processing:
    - Strips EXIF/metadata
    - Resizes to thumbnail
    - Converts to JPEG
    - Saves with UUID filename to prevent path traversal
    """
    # Check if file is present in request
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided. Use "file" field in multipart form data.'}), 400

    file = request.files['file']

    # Check if a file was actually selected
    if file.filename == '' or file.filename is None:
        return jsonify({'error': 'No file selected.'}), 400

    # Secure the filename and check extension
    original_filename = secure_filename(file.filename)
    if not allowed_extension(original_filename):
        return jsonify({
            'error': f'File type not allowed. Allowed types: {", ".join(app.config["ALLOWED_EXTENSIONS"])}'
        }), 400

    # Check MIME type from the request
    if file.content_type not in app.config['ALLOWED_MIME_TYPES']:
        return jsonify({
            'error': f'MIME type "{file.content_type}" not allowed.'
        }), 400

    # Read file into memory for validation
    file_bytes = file.read()

    # Check file size (double-check, MAX_CONTENT_LENGTH should catch this)
    if len(file_bytes) > app.config['MAX_CONTENT_LENGTH']:
        return jsonify({'error': 'File too large. Maximum size is 5 MB.'}), 413

    if len(file_bytes) == 0:
        return jsonify({'error': 'Empty file uploaded.'}), 400

    file_stream = BytesIO(file_bytes)

    # Validate actual file content using magic bytes
    detected_type = validate_image_content(file_stream)
    if detected_type is None:
        return jsonify({
            'error': 'File content does not match a valid image type. Possible file spoofing detected.'
        }), 400

    # Validate with PIL (catches corrupted images, decompression bombs, checks dimensions)
    file_stream.seek(0)
    img, error = validate_image_with_pil(file_stream)
    if error:
        return jsonify({'error': error}), 400

    # Generate a safe, unique filename (prevents path traversal and filename collisions)
    unique_filename = f"user_{user_id}_{uuid.uuid4().hex}.jpg"

    # Ensure the save path is within the upload folder (path traversal prevention)
    save_path = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
    save_path = os.path.abspath(save_path)

    if not save_path.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
        return jsonify({'error': 'Invalid file path detected.'}), 400

    # Remove old profile pictures for this user
    try:
        for existing_file in os.listdir(app.config['UPLOAD_FOLDER']):
            if existing_file.startswith(f"user_{user_id}_"):
                old_path = os.path.join(app.config['UPLOAD_FOLDER'], existing_file)
                old_path = os.path.abspath(old_path)
                if old_path.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
                    os.remove(old_path)
    except OSError:
        pass  # Non-critical, continue with upload

    # Process and save the image
    try:
        final_size = process_and_save_image(img, save_path)
    except Exception as e:
        return jsonify({'error': f'Failed to process image: {str(e)}'}), 500
    finally:
        img.close()

    # Verify the saved file size
    saved_file_size = os.path.getsize(save_path)

    return jsonify({
        'message': 'Profile picture uploaded successfully.',
        'filename': unique_filename,
        'url': f'/api/profile/picture/{unique_filename}',
        'size': {
            'width': final_size[0],
            'height': final_size[1],
            'file_size_bytes': saved_file_size,
        },
        'user_id': user_id,
    }), 201


@app.route('/api/profile/picture/<filename>', methods=['GET'])
def get_profile_picture(filename):
    """Serve a profile picture by filename."""
    # Secure the filename to prevent path traversal
    safe_filename = secure_filename(filename)
    if safe_filename != filename:
        return jsonify({'error': 'Invalid filename.'}), 400

    # Verify the file path is within the upload folder
    file_path = os.path.abspath(os.path.join(app.config['UPLOAD_FOLDER'], safe_filename))
    if not file_path.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
        return jsonify({'error': 'Invalid file path.'}), 400

    if not os.path.exists(file_path):
        return jsonify({'error': 'Profile picture not found.'}), 404

    return send_from_directory(
        app.config['UPLOAD_FOLDER'],
        safe_filename,
        mimetype='image/jpeg',
    )


@app.route('/api/profile/picture', methods=['DELETE'])
@require_auth
def delete_profile_picture(user_id):
    """Delete the profile picture for the authenticated user."""
    deleted = False
    try:
        for existing_file in os.listdir(app.config['UPLOAD_FOLDER']):
            if existing_file.startswith(f"user_{user_id}_"):
                file_path = os.path.abspath(
                    os.path.join(app.config['UPLOAD_FOLDER'], existing_file)
                )
                if file_path.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
                    os.remove(file_path)
                    deleted = True
    except OSError as e:
        return jsonify({'error': f'Failed to delete profile picture: {str(e)}'}), 500

    if deleted:
        return jsonify({'message': 'Profile picture deleted successfully.'}), 200
    else:
        return jsonify({'error': 'No profile picture found for this user.'}), 404


@app.errorhandler(413)
def request_entity_too_large(error):
    """Handle file too large errors."""
    return jsonify({
        'error': f'File too large. Maximum upload size is {app.config["MAX_CONTENT_LENGTH"] // (1024 * 1024)} MB.'
    }), 413


@app.errorhandler(400)
def bad_request(error):
    return jsonify({'error': 'Bad request.'}), 400


@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error.'}), 500


